// Input validation helpers for API endpoints.
//
// Each validator returns an array of error message strings. An empty array
// means the input is valid. Route handlers collect errors from multiple
// validators and, if any exist, return a 400 with the full list so the
// caller can see every validation failure at once.

// RFC 5321 caps the full email length at 254 characters.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Pragmatic email regex: requires a local part, "@", a domain with at least
// one dot, and a TLD of 2+ chars. Not a full RFC 5322 parser, but catches
// the vast majority of malformed input.
const EMAIL_PATTERN = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(fields, source) {
  const errors = [];
  for (const field of fields) {
    if (!isPresent(source[field])) {
      errors.push(`Field "${field}" is required`);
    }
  }
  return errors;
}

function validateId(value, fieldName = 'id') {
  const errors = [];
  if (!isPresent(value)) {
    return errors; // presence handled by validateRequired
  }
  // Accept numeric strings (from path/query params) and numbers.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber)) {
    errors.push(`Field "${fieldName}" must be numeric`);
  } else if (!Number.isInteger(asNumber)) {
    errors.push(`Field "${fieldName}" must be an integer`);
  } else if (asNumber <= 0) {
    errors.push(`Field "${fieldName}" must be a positive integer`);
  }
  return errors;
}

function validateName(value, fieldName = 'name') {
  const errors = [];
  if (!isPresent(value)) {
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`Field "${fieldName}" must be a string`);
    return errors;
  }
  const trimmed = value.trim();
  if (trimmed.length < NAME_MIN_LENGTH) {
    errors.push(
      `Field "${fieldName}" must be at least ${NAME_MIN_LENGTH} character(s)`
    );
  }
  if (value.length > NAME_MAX_LENGTH) {
    errors.push(
      `Field "${fieldName}" must be at most ${NAME_MAX_LENGTH} characters`
    );
  }
  return errors;
}

function validateEmail(value, fieldName = 'email') {
  const errors = [];
  if (!isPresent(value)) {
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`Field "${fieldName}" must be a string`);
    return errors;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(
      `Field "${fieldName}" must be at most ${EMAIL_MAX_LENGTH} characters`
    );
  }
  if (!EMAIL_PATTERN.test(value)) {
    errors.push(`Field "${fieldName}" must be a valid email address`);
  }
  return errors;
}

// Convenience wrapper: validates a user-shaped payload (id optional).
// `options.requireId` controls whether id must be present.
function validateUserPayload(payload, options = {}) {
  const { requireId = false } = options;
  if (payload === null || typeof payload !== 'object') {
    return ['Request body must be a JSON object'];
  }
  const requiredFields = ['name', 'email'];
  if (requireId) requiredFields.unshift('id');

  return [
    ...validateRequired(requiredFields, payload),
    ...(isPresent(payload.id) ? validateId(payload.id) : []),
    ...validateName(payload.name),
    ...validateEmail(payload.email),
  ];
}

// Express middleware factory: runs `validator(req)` and short-circuits with
// a 400 + descriptive error list if anything failed.
function validate(validator) {
  return (req, res, next) => {
    const errors = validator(req) || [];
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  isPresent,
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  validateUserPayload,
  validate,
};

