// validation.js
// Reusable input validation helpers for API route handlers.
//
// Each rule function returns null on success or a string describing the
// failure. `validate(input, schema)` runs a set of rules and returns
// { valid: boolean, errors: string[] } so route handlers can stay clean.

// RFC 5321 caps the total email address length at 254 characters.
const MAX_EMAIL_LENGTH = 254;
const MIN_NAME_LENGTH = 1;
const MAX_NAME_LENGTH = 100;

// Pragmatic email regex: local@domain.tld with no whitespace. Not a full
// RFC 5322 grammar, but sufficient to reject obviously malformed input.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

// --- Field-level validators -------------------------------------------------

function validateId(value, { field = 'id' } = {}) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  // Accept numbers or numeric strings (path/query params arrive as strings).
  const n = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(n) || !Number.isInteger(n) || n <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

function validateName(value, { field = 'name' } = {}) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length < MIN_NAME_LENGTH || value.length > MAX_NAME_LENGTH) {
    return `${field} must be between ${MIN_NAME_LENGTH} and ${MAX_NAME_LENGTH} characters`;
  }
  return null;
}

function validateEmail(value, { field = 'email' } = {}) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length > MAX_EMAIL_LENGTH) {
    return `${field} must be at most ${MAX_EMAIL_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

// --- Schema runner ----------------------------------------------------------

// Built-in rule map keyed by type name, so schemas stay declarative.
const RULES = {
  id: validateId,
  name: validateName,
  email: validateEmail,
};

/**
 * Run a declarative schema against an input object.
 *
 * @param {object} input  - Source of values (e.g. req.body, req.params).
 * @param {object} schema - Map of fieldName -> ruleName or { rule, field }.
 *                          Example: { id: 'id', name: 'name', email: 'email' }
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validate(input, schema) {
  const errors = [];
  const source = input && typeof input === 'object' ? input : {};

  for (const [fieldName, spec] of Object.entries(schema)) {
    const ruleName = typeof spec === 'string' ? spec : spec.rule;
    const rule = RULES[ruleName];
    if (!rule) {
      throw new Error(`Unknown validation rule: ${ruleName}`);
    }
    const err = rule(source[fieldName], { field: fieldName });
    if (err) errors.push(err);
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Express middleware factory: validates req[source] against a schema and
 * short-circuits with a descriptive 400 response on failure.
 *
 * @param {'body'|'params'|'query'} source
 * @param {object} schema
 */
function validateRequest(source, schema) {
  return (req, res, next) => {
    const { valid, errors } = validate(req[source], schema);
    if (!valid) {
      return res.status(400).json({
        error: 'Validation failed',
        source,
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  validate,
  validateRequest,
  validateId,
  validateName,
  validateEmail,
  // Exported constants so tests and callers can reference the same limits.
  MAX_EMAIL_LENGTH,
  MIN_NAME_LENGTH,
  MAX_NAME_LENGTH,
};

