// Validation helper module
// Provides reusable validators and a helper to validate an object against
// a schema, collecting descriptive error messages.

// RFC 5321 practical limit for the full address
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Reasonably strict email regex. Not a full RFC 5322 parser, but good enough
// for request validation and consistent with common libraries.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(fieldName, value, errors) {
  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return false;
  }
  return true;
}

function validateId(fieldName, value, errors) {
  // Accept numbers or numeric strings; reject anything else.
  if (typeof value === 'number') {
    if (!Number.isFinite(value) || !Number.isInteger(value) || value <= 0) {
      errors.push(`${fieldName} must be a positive integer`);
      return false;
    }
    return true;
  }
  if (typeof value === 'string') {
    if (!/^\d+$/.test(value)) {
      errors.push(`${fieldName} must be numeric`);
      return false;
    }
    const parsed = Number(value);
    if (!Number.isInteger(parsed) || parsed <= 0) {
      errors.push(`${fieldName} must be a positive integer`);
      return false;
    }
    return true;
  }
  errors.push(`${fieldName} must be numeric`);
  return false;
}

function validateName(fieldName, value, errors) {
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return false;
  }
  const trimmed = value.trim();
  if (trimmed.length < NAME_MIN_LENGTH || trimmed.length > NAME_MAX_LENGTH) {
    errors.push(
      `${fieldName} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`
    );
    return false;
  }
  return true;
}

function validateEmail(fieldName, value, errors) {
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return false;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(`${fieldName} must be at most ${EMAIL_MAX_LENGTH} characters`);
    return false;
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
    return false;
  }
  return true;
}

// Known field types for schema-based validation.
const FIELD_VALIDATORS = {
  id: validateId,
  name: validateName,
  email: validateEmail,
};

/**
 * Validate an input object against a schema.
 *
 * schema example:
 *   { id: { required: true }, name: { required: true }, email: { required: false } }
 *
 * Returns: { valid: boolean, errors: string[] }
 */
function validate(input, schema) {
  const errors = [];
  const source = input && typeof input === 'object' ? input : {};

  for (const [field, rules] of Object.entries(schema)) {
    const value = source[field];
    const validator = FIELD_VALIDATORS[field];

    if (!validator) {
      // Unknown field type in schema — treat as a programmer error, but do
      // not throw at request time.
      continue;
    }

    if (rules.required) {
      if (!validateRequired(field, value, errors)) {
        continue; // Skip type check when value is absent.
      }
    } else if (!isPresent(value)) {
      continue; // Optional and not provided — skip.
    }

    validator(field, value, errors);
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Express helper: if validation fails, send a 400 response and return true
 * (telling the handler to stop). Otherwise return false.
 */
function respondIfInvalid(res, input, schema) {
  const { valid, errors } = validate(input, schema);
  if (!valid) {
    res.status(400).json({
      error: 'Validation failed',
      details: errors,
    });
    return true;
  }
  return false;
}

module.exports = {
  validate,
  respondIfInvalid,
  validateId,
  validateName,
  validateEmail,
  validateRequired,
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};

