// Validation helper module
// Provides composable validators that collect errors rather than throwing,
// so a single request can report every field that failed in one response.

// RFC 5321 caps the full email address at 254 characters.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Reasonable email regex. Not a full RFC 5322 parser, but catches the
// common malformed cases (missing @, missing TLD, whitespace, etc.).
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Require a field to be present (not undefined, null, or empty string).
 */
function validateRequired(value, fieldName, errors) {
  if (value === undefined || value === null || value === '') {
    errors.push(`${fieldName} is required`);
    return false;
  }
  return true;
}

/**
 * Validate an id: must be present and numeric (integer, >= 0).
 * Accepts numeric strings (from URL params) and coerces.
 */
function validateId(value, fieldName, errors) {
  if (!validateRequired(value, fieldName, errors)) return false;

  const num = Number(value);
  if (!Number.isInteger(num) || num < 0) {
    errors.push(`${fieldName} must be a non-negative integer`);
    return false;
  }
  return true;
}

/**
 * Validate a name: required, string, length 1-100.
 */
function validateName(value, fieldName, errors) {
  if (!validateRequired(value, fieldName, errors)) return false;

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return false;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    errors.push(
      `${fieldName} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`
    );
    return false;
  }
  return true;
}

/**
 * Validate an email: required, string, <=254 chars, matches email format.
 */
function validateEmail(value, fieldName, errors) {
  if (!validateRequired(value, fieldName, errors)) return false;

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return false;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(`${fieldName} must be at most ${EMAIL_MAX_LENGTH} characters`);
    return false;
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
    return false;
  }
  return true;
}

/**
 * Run a list of validator thunks; return { valid, errors }.
 * Each thunk should push into the shared `errors` array.
 */
function runValidators(validators) {
  const errors = [];
  for (const v of validators) v(errors);
  return { valid: errors.length === 0, errors };
}

/**
 * Express middleware factory. Pass a function that receives (req) and returns
 * a list of validator thunks. Responds 400 with a descriptive error payload
 * if any validation fails; otherwise calls next().
 *
 * Example:
 *   app.post('/users', validate(req => [
 *     errs => validateName(req.body.name, 'name', errs),
 *     errs => validateEmail(req.body.email, 'email', errs),
 *   ]), handler);
 */
function validate(buildValidators) {
  return (req, res, next) => {
    const thunks = buildValidators(req);
    const { valid, errors } = runValidators(thunks);
    if (!valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  runValidators,
  validate,
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};

